class Solution:
    def beautifulSubstrings(self, s, k):
        n = len(s)
        vowels_set = set('aeiou')
        count = 0
        for length in range(2, n + 1, 2):
            v = sum(1 for ch in s[0:length] if ch in vowels_set)
            c = length - v
            if v == c and (v * c) % k == 0:
                count += 1
            for start in range(1, n - length + 1):
                out_ch = s[start - 1]
                in_ch = s[start + length - 1]
                if out_ch in vowels_set:
                    v -= 1
                if in_ch in vowels_set:
                    v += 1
                c = length - v
                if v == c and (v * c) % k == 0:
                    count += 1
        return count

