class Solution:
    def beautifulSubstrings(self, s, k):
        n = len(s)
        vowels_set = set('aeiou')
        prefix = [0] * (n + 1)
        for i, ch in enumerate(s):
            prefix[i + 1] = prefix[i] + (1 if ch in vowels_set else 0)
        count = 0
        for i in range(n):
            for j in range(i + 1, n + 1):
                length = j - i
                if length % 2 != 0:
                    continue
                v = prefix[j] - prefix[i]
                c = length - v
                if v == c and (v * c) % k == 0:
                    count += 1
        return count

