var beautifulSubstrings = function(s, k) {
    const n = s.length;
    const isVowel = (c) => c === 'a' || c === 'e' || c === 'i' || c === 'o' || c === 'u';
    const prefix = new Array(n + 1).fill(0);
    for (let i = 0; i < n; i++) {
        prefix[i + 1] = prefix[i] + (isVowel(s[i]) ? 1 : 0);
    }
    let count = 0;
    for (let i = 0; i < n; i++) {
        for (let j = i + 1; j <= n; j++) {
            const length = j - i;
            if (length % 2 !== 0) continue;
            const v = prefix[j] - prefix[i];
            const c = length - v;
            if (v === c && (v * c) % k === 0) count++;
        }
    }
    return count;
};
